// GST Invoice Calculator

const unitPrice  = 1250;       // price before tax
const quantity   = 4;          // number of units
const GST_RATE   = 0.18;       // 18% GST

// Basic arithmetic
const subtotal   = unitPrice * quantity;   // 5000
const gstAmount  = subtotal * GST_RATE;    // 900
const grandTotal = subtotal + gstAmount;   // 5900

console.log("Unit Price :₹", unitPrice);
console.log("Quantity   :",   quantity);
console.log("Subtotal   :₹", subtotal);
console.log("GST (18%)  :₹", gstAmount);
console.log("Grand Total:₹", grandTotal);

// Math methods
const rawAvgPerUnit = grandTotal / quantity;         // 1475 exactly
const rounded       = Math.round(rawAvgPerUnit);     // 1475
const flooredDis    = Math.floor(grandTotal * 0.05); // floor of 5% discount

console.log("Avg per unit:", rounded);
console.log("5% discount :", flooredDis);

// Modulo — check if quantity is even
console.log("Even quantity?", quantity % 2 === 0);

